async def transient_failure_step(step, context): nonlocal failure_count if step["name"] == "step2": failure_count += 1 if failure_count <= 2: # Fail first two attempts raise Exception("Transient failure") return await original_execute_step(step, context)
workflow.execute_step = transient_failure_step
